-- ========== West-Med (KZ) демо-данные ==========




   DATE '2026-08-15', 45000000.00, 'KZT', 'Закуп УЗИ-аппарата для горбольницы №1 (Алматы)', 'KZ');

-- KZ дистрибьюторы — привязка к типам оборудования (УЗИ, ИВЛ) для bulk-КП "eligible distributors"
SELECT d.id, et.id FROM distributor d, equipment_type et
WHERE d.name IN ('ТОО «МедСнаб Казахстан»','ТОО «Алматы Медтехника»')
  AND et.name IN ('УЗИ','ИВЛ');

-- KZ частная заявка (демо потока «частники»: tender source=PRIVATE_REQUEST, deadline null)
   'NEW', 'PRIVATE_REQUEST', 'KZ', 'Запрос от частной клиники: ЭКГ и расходники');


-- KZ поставщики — бренды (для подбора поставщиков по брендам в частных заявках, блок C)
SELECT id, b FROM distributor, (VALUES ('Mindray'), ('Hamilton Medical'), ('Drager')) AS x(b)
WHERE name = 'ТОО «МедСнаб Казахстан»';
SELECT id, b FROM distributor, (VALUES ('Philips'), ('GE Healthcare')) AS x(b)
WHERE name = 'ТОО «Алматы Медтехника»';
